package org.apache.commons.math.linear;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = {"src/test/resources/requirement.feature"},
    glue = {"org.apache.commons.math.linear.steps"},
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.apache.commons.math.linear.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.math.linear.*;
import org.junit.Assert;

import java.util.List;

import static org.junit.Assert.assertEquals;

public class StepDefs {
    private RealMatrix originalMatrix;
    private SingularValueDecomposition svd;
    private double tolerance;

    @Given("a 3x3 real matrix defined as:")
    public void given_a_3x3_real_matrix(List<List<Double>> matrixData) {
        // Convert the 2D list to a 2D array for MatrixUtils
        double[][] data = new double[3][3];
        for (int i = 0; i < 3; i++) {
            for (int j = 0; j < 3; j++) {
                data[i][j] = matrixData.get(i).get(j);
            }
        }
        this.originalMatrix = MatrixUtils.createRealMatrix(data);
    }

    @When("I compute the Singular Value Decomposition of the matrix")
    public void when_i_compute_the_singular_value_decomposition() {
        try {
            this.svd = new SingularValueDecompositionImpl(this.originalMatrix);
        } catch (Exception e) {
            // Handle the exception in case of any errors during decomposition
            System.out.println("Exception during SVD: " + e.getMessage());
            throw e;
        }
    }

    @Then("the product of U, S, and VT should equal the original matrix within a tolerance of {double}")
    public void then_the_product_of_U_S_and_VT_should_equal_original_matrix(double tolerance) {
        // Get the U, S, and V matrices from the SVD
        RealMatrix u = svd.getU();
        RealMatrix s = svd.getS();
        RealMatrix v = svd.getV();

        // Compute U * S * VT (where VT is transpose of V)
        RealMatrix product = u.multiply(s).multiply(v.transpose());

        // Calculate the difference between the reconstructed matrix and the original
        RealMatrix difference = product.subtract(originalMatrix);

        // Get the norm of the difference matrix to check if it's within tolerance
        double norm = difference.getNorm();

        // Assert that the norm is within the specified tolerance
        assertEquals(0.0, norm, tolerance);
    }
}

